; 
; Top-selling products refers to the products with the highest total quantity sold.
; Corresponding farm activities include planting, harvesting, or other activities related to the top-selling products.

sql:
SELECT COUNT(activity_id) AS activity_count
FROM farm_activities
WHERE farm_id = 0;

SELECT first_name, last_name, email
FROM farmers
ORDER BY last_name, first_name;

SELECT farm_id, COUNT(activity_id) AS activity_count
FROM farm_activities
GROUP BY farm_id;

SELECT MAX(event_date) AS most_recent_event_date
FROM farm_events
WHERE farm_id = 1;

SELECT COUNT(event_id) AS event_count
FROM farm_events
WHERE farm_id = 0;

SELECT farm_name
FROM farms
ORDER BY farm_name;
